function VibeTabs(selector,options){const defaults={activeTabClass:"VibeTabs--active",remember:false};Object.assign(this,defaults,options);this.tabParent=document.querySelector(selector);if(!this.tabParent){console.error(`VibeTabs: No container found for selector ${selector}`);return}this.originalHTML=this.tabParent.innerHTML;this.tabChilds=this.tabParent.children;if(this.tabChilds.length===0){console.error("VibeTabs: No tabs found inside the parent container");return}this.activeTabIndex=0;this.tabTargets=[];this.panels=[];for(let i=0;i<this.tabChilds.length;i++){if(this.tabChilds[i].classList.contains(this.activeTabClass))this.activeTabIndex=i;const aTag=this.tabChilds[i].querySelector("a");const target=aTag.getAttribute("href");aTag.onclick=event=>this._handleTabClick(event,target);aTag.addEventListener("click",()=>{this.switch(target)});const panel=document.querySelector(target);if(!panel){console.error(`VibeTabs: No panel found for selector ${target}`);return}this.panels.push(panel);this.tabTargets.push(target)}const savedTabIndex=location.hash;if(this.remember&&savedTabIndex)this.activeTabIndex=this.tabTargets.indexOf(savedTabIndex);if(this.activeTabIndex===-1)this.activeTabIndex=0;this.switch(this.tabTargets[this.activeTabIndex])}VibeTabs.prototype._setTab=function(index){this.tabChilds[index].classList.add(this.activeTabClass);this.panels[index].classList.remove("VibeTabs--hidden")};VibeTabs.prototype._removeTab=function(index){this.tabChilds[index].classList.remove(this.activeTabClass);this.panels[index].classList.add("VibeTabs--hidden")};VibeTabs.prototype._handleTabClick=function(event,selector){event.preventDefault();this.switch(selector)};VibeTabs.prototype.switch=function(input){let idx;if(typeof input!=="string"){idx=Array.from(this.tabChilds).findIndex(element=>element===input.closest("li"));if(idx===-1){console.error(`VibeTabs: Cannot switch because element does not exists`);return}}else{idx=this.tabTargets.indexOf(input);if(idx===-1){console.error(`VibeTabs: Cannot switch because tab with ${input} does not exists`);return}}for(let i=0;i<this.tabChilds.length;i++)if(i===idx)this._setTab(i);else this._removeTab(i);this.activeTabIndex=idx;if(this.remember)history.replaceState(null,null,this.tabTargets[idx])};VibeTabs.prototype.destroy=function(){this.tabParent.innerHTML=this.originalHTML;for(let panel of this.panels)panel.classList.remove("VibeTabs--hidden");this.tabParent=null;this.tabChilds=null;this.tabTargets=null;this.panels=null};